cpp_unit:
long parse_positive(long n){
    if (n <= 0) throw std::runtime_error("must be positive");
    long total = 0;
    for (long i = 1; i <= n; ++i) total += i;
    return total;
}

mojo_unit:
def parse_positive(n: Int) raises -> Int:
    if n <= 0:
        raise Error("must be positive")
    var total = 0
    for i in range(1, n + 1):
        total += i
    return total

